
'use server';

import { collection, getDocs, query, where } from 'firebase/firestore';
import { db } from '@/lib/firebase';
import type { Driver } from './drivers';
import type { Student } from './students';

export interface UserData {
    name: string;
    email: string;
    role: 'admin' | 'driver' | 'parent';
    avatar?: string;
}

const ADMIN_EMAILS = ['admin@yellowtransit.com']; // Predefined admin accounts

/**
 * Determines the role of a user based on their email.
 * @param email The user's email address.
 * @returns The user's role: 'admin', 'driver', 'parent', or null if not found.
 */
export const getUserRole = async (email: string): Promise<'admin' | 'driver' | 'parent' | null> => {
    if (ADMIN_EMAILS.includes(email)) {
        return 'admin';
    }

    // Check if user is a driver
    const driversCol = collection(db, 'drivers');
    const driverQuery = query(driversCol, where('email', '==', email));
    const driverSnapshot = await getDocs(driverQuery);
    if (!driverSnapshot.empty) {
        return 'driver';
    }

    // Check if user is a parent
    const studentsCol = collection(db, 'students');
    const parentQuery = query(studentsCol, where('parent.email', '==', email));
    const parentSnapshot = await getDocs(parentQuery);
    if (!parentSnapshot.empty) {
        return 'parent';
    }

    return null;
};


/**
 * Fetches user data based on their email.
 * @param email The user's email address.
 * @returns UserData object or null if not found.
 */
export const getUserData = async (email: string): Promise<UserData | null> => {
    const role = await getUserRole(email);

    if (!role) {
        return null;
    }

    if (role === 'admin') {
        return {
            name: 'Admin User',
            email,
            role: 'admin',
            avatar: `https://placehold.co/40x40.png`,
        };
    }

    if (role === 'driver') {
        const driversCol = collection(db, 'drivers');
        const q = query(driversCol, where('email', '==', email));
        const snapshot = await getDocs(q);
        if (!snapshot.empty) {
            const driverData = snapshot.docs[0].data() as Omit<Driver, 'id'>;
            return {
                name: driverData.name,
                email,
                role: 'driver',
                avatar: driverData.avatar,
            };
        }
    }

    if (role === 'parent') {
        const studentsCol = collection(db, 'students');
        const q = query(studentsCol, where('parent.email', '==', email));
        const snapshot = await getDocs(q);
        if (!snapshot.empty) {
            const studentData = snapshot.docs[0].data() as Omit<Student, 'id'>;
            return {
                name: studentData.parent.name,
                email,
                role: 'parent',
                avatar: `https://placehold.co/40x40.png`,
            };
        }
    }

    return null;
}
